# JavaScript Debounce 函数

```javascript
/**
 * 创建一个 debounce（防抖）函数
 * @param {Function} fn - 要执行的函数
 * @param {number} delay - 延迟时间（毫秒）
 * @param {Object} [options] - 配置选项
 * @param {boolean} [options.leading=false] - 是否在延迟开始前立即执行一次
 * @param {boolean} [options.trailing=true] - 是否在延迟结束后执行（leading 为 true 时仍可触发 trailing）
 * @param {number} [options.maxWait] - 最大等待时间，超过此时间强制执行
 * @returns {Function} 防抖后的函数
 */
function debounce(fn, delay, options = {}) {
  const { leading = false, trailing = true, maxWait } = options;

  let timer = null;           // setTimeout 句柄
  let lastArgs = null;        // 最后一次调用的参数
  let lastThis = null;        // 最后一次调用的 this
  let lastCallTime = null;    // 最后一次调用的时间戳
  let lastInvokeTime = 0;     // 最后一次执行的时间戳
  let result;                 // fn 的返回值

  // 是否已超时等待上限
  const useMaxWait = maxWait && maxWait > 0;

  // 清除定时器
  function clearTimer() {
    if (timer !== null) {
      clearTimeout(timer);
      timer = null;
    }
  }

  // 执行函数（leading 或 maxWait 触发）
  function invokeFunc(time) {
    const args = lastArgs;
    const thisArg = lastThis;

    lastArgs = null;
    lastThis = null;
    lastInvokeTime = time;

    result = fn.apply(thisArg, args);
    return result;
  }

  // 判断是否应该立即执行（leading）
  function shouldInvokeLeading(time) {
    if (!lastCallTime) return true;          // 首次调用
    const timeSinceLastCall = time - lastCallTime;
    const timeSinceLastInvoke = time - lastInvokeTime;

    return (
      timeSinceLastCall >= delay ||
      timeSinceLastCall < 0 ||               // 系统时间回拨
      (useMaxWait && timeSinceLastInvoke >= maxWait)
    );
  }

  // 计算剩余等待时间
  function remainingWait(time) {
    const timeSinceLastCall = time - lastCallTime;
    const timeSinceLastInvoke = time - lastInvokeTime;
    const timeWaiting = useMaxWait ? delay - timeSinceLastCall : delay - timeSinceLastCall;

    // 如果设定了 maxWait，且已经超过 maxWait 未执行，则立即触发
    if (useMaxWait) {
      const maxWaitRemaining = maxWait - timeSinceLastInvoke;
      return maxWaitRemaining < timeWaiting ? maxWaitRemaining : timeWaiting;
    }

    return timeWaiting;
  }

  // 启动定时器（trailing edge 触发）
  function startTimer(time) {
    const wait = remainingWait(time);

    // 如果 maxWait 已耗尽，立即执行
    if (useMaxWait && wait <= 0) {
      clearTimer();
      return invokeFunc(time);
    }

    clearTimer();
    timer = setTimeout(() => {
      const timeNow = Date.now();
      // 再次判断是否应该执行（避免计时器回调时又被取消）
      const timeSinceLastCall = timeNow - lastCallTime;
      const shouldExecute = trailing && timeSinceLastCall >= delay;

      if (shouldExecute) {
        clearTimer();
        invokeFunc(timeNow);
      } else if (lastCallTime !== null) {
        // 如果还没到时间，重新计时
        startTimer(lastCallTime);
      }
    }, wait);

    return result;
  }

  // 核心防抖函数
  function debounced(...args) {
    const time = Date.now();
    const isInvoking = shouldInvokeLeading(time);

    lastArgs = args;
    lastThis = this;
    lastCallTime = time;

    // 首次调用 或 leading edge 触发
    if (isInvoking) {
      // 如果没有定时器在跑（代表 trailing edge 不会执行），直接执行
      if (timer === null && leading) {
        lastInvokeTime = time;
        result = fn.apply(this, args);
        lastArgs = null;
        lastThis = null;
      } else {
        // 有定时器时，用 maxWait 机制强制触发
        if (useMaxWait) {
          clearTimer();
          startTimer(time);
        }
      }
    }

    // 如果没有定时器，且 trailing 模式开启，启动 trailing timer
    if (timer === null && trailing) {
      startTimer(time);
    }

    return result;
  }

  /**
   * 取消防抖，未执行的调用不会被执行
   */
  debounced.cancel = function () {
    clearTimer();
    lastArgs = null;
    lastThis = null;
    lastCallTime = null;
    lastInvokeTime = 0;
  };

  /**
   * 立即执行 pending 中的调用
   */
  debounced.flush = function () {
    if (timer !== null && lastArgs) {
      const time = Date.now();
      clearTimer();
      return invokeFunc(time);
    }
    return result;
  };

  /**
   * 是否还有 pending 的调用
   */
  debounced.pending = function () {
    return timer !== null;
  };

  return debounced;
}
```

---

## 使用示例

### 1️⃣ 基础用法（trailing，默认）

```javascript
const saveInput = debounce((text) => {
  console.log('保存:', text);
}, 300);

// 用户连续输入，只在最后停顿时保存
saveInput('a');
saveInput('ab');
saveInput('abc');  // 只有这次在 300ms 后执行
```

### 2️⃣ leading（立即执行，然后防抖）

```javascript
const clickBtn = debounce(
  () => console.log('按钮点击'),
  500,
  { leading: true, trailing: false }
);

// 连续点击，只有第一次立即执行，后面被防抖掉
clickBtn(); // 立即执行
clickBtn(); // 忽略
clickBtn(); // 忽略
```

### 3️⃣ leading + trailing（首次立即执行，最后再执行一次）

```javascript
const logSearch = debounce(
  (q) => fetch(`/search?q=${q}`),
  400,
  { leading: true, trailing: true }
);
```

### 4️⃣ maxWait（最大等待时间，防止饥饿）

```javascript
const handleScroll = debounce(
  () => { /* 复杂计算 */ },
  300,
  { maxWait: 1000 }
);
// 即使用户一直在滚动，最多 1000ms 也会强制执行一次
```

### 5️⃣ React Hook 封装

```javascript
import { useMemo } from 'react';

function useDebounce(fn, delay, options) {
  return useMemo(
    () => debounce(fn, delay, options),
    [fn, delay, JSON.stringify(options)]
  );
}
```

---

## 常见场景

| 场景 | 推荐 delay | 说明 |
|------|-----------|------|
| 搜索输入框 | 300–500ms | 用户停止输入后再请求 |
| 窗口 resize | 150–300ms | 避免频繁重排 |
| 按钮双击防抖 | 300ms, leading | 第一次立即执行，后续忽略 |
| 自动保存草稿 | 1000–2000ms | 间隔写入，不阻塞编辑 |
| 滚动加载 | 200ms + maxWait: 1000 | 保证至少每秒触发一次 |

---

